+package com.khoablabla.pvpbot.combat;
+
+import net.citizensnpcs.api.npc.NPC;
+
+import org.bukkit.Particle;
+import org.bukkit.entity.LivingEntity;
+import org.bukkit.entity.Player;
+import org.bukkit.util.Vector;
+
+public class MeleeAttackController {
+
+    private static final double MELEE_RANGE = 3.5;
+    private static final int ATTACK_COOLDOWN_TICKS = 10;
+
+    private int attackCooldown = 0;
+    private boolean jumpTriggered = false;
+    private boolean critsEnabled = true;
+
+    public void setCritsEnabled(boolean enabled) {
+        this.critsEnabled = enabled;
+    }
+
+    public void tick(NPC npc, LivingEntity target) {
+        if (attackCooldown > 0) attackCooldown--;
+
+        if (!npc.isSpawned() || !(npc.getEntity() instanceof Player botPlayer)) return;
+
+        double distance = botPlayer.getLocation().distance(target.getLocation());
+        if (distance > MELEE_RANGE) return;
+
+        if (jumpTriggered) {
+            Vector vel = botPlayer.getVelocity();
+            if (vel.getY() < 0) {
+                performAttack(botPlayer, target, true);
+                jumpTriggered = false;
+            }
+            return;
+        }
+
+        if (attackCooldown > 0) return;
+
+        if (critsEnabled) {
+            botPlayer.setVelocity(new Vector(0, 0.42, 0));
+            jumpTriggered = true;
+        } else {
+            performAttack(botPlayer, target, false);
+        }
+    }
+
+    private void performAttack(Player botPlayer, LivingEntity target, boolean critical) {
+        botPlayer.swingMainHand();
+
+        double damage = critical ? 6.0 : 4.0;
+
+        if (critical) {
+            target.getWorld().spawnParticle(Particle.CRIT, target.getEyeLocation(), 8, 0.3, 0.3, 0.3, 0.05);
+        }
+
+        target.damage(damage, botPlayer);
+        attackCooldown = ATTACK_COOLDOWN_TICKS;
+    }
+}

