package com.khoablabla.pvpbot.combat;

import net.citizensnpcs.api.npc.NPC;

import org.bukkit.GameMode;
import org.bukkit.entity.Entity;
import org.bukkit.entity.LivingEntity;
import org.bukkit.entity.Player;

import java.util.Comparator;

public final class CombatTargetSelector {

    private static final double DEFAULT_RANGE = 10.0;

    public CombatTargetSelector() {
    }

    public LivingEntity findTarget(NPC npc) {
        return findTarget(npc, DEFAULT_RANGE);
    }

    public LivingEntity findTarget(NPC npc, double range) {
        if (!npc.isSpawned()) return null;

        Entity npcEntity = npc.getEntity();
        if (!(npcEntity instanceof LivingEntity bot)) return null;

        return bot.getNearbyEntities(range, range, range).stream()
                .filter(e -> e instanceof LivingEntity living && !living.isDead())
                .filter(e -> !e.equals(npcEntity))
                .filter(e -> !(e instanceof Player p && (p.getGameMode() == GameMode.CREATIVE || p.getGameMode() == GameMode.SPECTATOR)))
                .map(e -> (LivingEntity) e)
                .min(Comparator.comparingDouble(e -> e.getLocation().distanceSquared(npcEntity.getLocation())))
                .orElse(null);
    }
}

package com.khoablabla.pvpbot.movement;

import net.citizensnpcs.api.npc.NPC;

import org.bukkit.Location;
import org.bukkit.entity.LivingEntity;
import org.bukkit.entity.Player;
import org.bukkit.util.Vector;

public class BotMovementController {

    private static final double BUNNY_HOP_INTERVAL = 20;
    private static final double STRAFE_DISTANCE = 3.5;
    private static final double STRAFE_RADIUS = 2.0;
    private static final int STRAFE_INTERVAL = 25;

    private int tickCounter = 0;
    private int strafeTimer = 0;
    private boolean strafing = false;

    public void update(NPC npc, LivingEntity target) {
        tickCounter++;
        strafeTimer--;

        if (!npc.isSpawned() || !(npc.getEntity() instanceof Player botPlayer)) return;

        double distance = botPlayer.getLocation().distance(target.getLocation());

        if (distance > STRAFE_DISTANCE) {
            strafing = false;
            npc.getNavigator().setTarget(target, true);

            if (tickCounter % BUNNY_HOP_INTERVAL == 0 && botPlayer.isOnGround()) {
                Vector dir = target.getLocation().toVector()
                        .subtract(botPlayer.getLocation().toVector());
                dir.setY(0).normalize().multiply(0.4);
                dir.setY(0.42);
                botPlayer.setVelocity(dir);
            }
        } else {
            if (!strafing || strafeTimer <= 0) {
                Location strafeDest = calculateStrafePoint(
                        botPlayer.getLocation(), target.getLocation(), STRAFE_RADIUS);
                npc.getNavigator().setTarget(strafeDest);
                npc.getNavigator().getLocalParameters().lookAtFunction(
                        target::getLocation);
                strafing = true;
                strafeTimer = STRAFE_INTERVAL;
            }
        }
    }

    public void stop(NPC npc) {
        if (npc.isSpawned()) {
            npc.getNavigator().cancelNavigation();
        }
        strafing = false;
    }

    private Location calculateStrafePoint(Location botLoc, Location targetLoc, double radius) {
        Vector toBot = botLoc.toVector().subtract(targetLoc.toVector());
        toBot.setY(0);

        if (toBot.lengthSquared() < 0.01) {
            toBot.setX(radius);
        }

        Vector perp = new Vector(-toBot.getZ(), 0, toBot.getX()).normalize().multiply(radius);
        return targetLoc.clone().add(perp);
    }
}

package com.khoablabla.pvpbot.combat;

import net.citizensnpcs.api.npc.NPC;

import org.bukkit.Particle;
import org.bukkit.entity.LivingEntity;
import org.bukkit.entity.Player;
import org.bukkit.util.Vector;

public class MeleeAttackController {

    private static final double MELEE_RANGE = 3.5;
    private static final int ATTACK_COOLDOWN_TICKS = 10;

    private int attackCooldown = 0;
    private boolean jumpTriggered = false;
    private boolean critsEnabled = true;

    public void setCritsEnabled(boolean enabled) {
        this.critsEnabled = enabled;
    }

    public void tick(NPC npc, LivingEntity target) {
        if (attackCooldown > 0) attackCooldown--;

        if (!npc.isSpawned() || !(npc.getEntity() instanceof Player botPlayer)) return;

        double distance = botPlayer.getLocation().distance(target.getLocation());
        if (distance > MELEE_RANGE) return;

        if (jumpTriggered) {
            Vector vel = botPlayer.getVelocity();
            if (vel.getY() < 0) {
                performAttack(botPlayer, target, true);
                jumpTriggered = false;
            }
            return;
        }

        if (attackCooldown > 0) return;

        if (critsEnabled) {
            botPlayer.setVelocity(new Vector(0, 0.42, 0));
            jumpTriggered = true;
        } else {
            performAttack(botPlayer, target, false);
        }
    }

    private void performAttack(Player botPlayer, LivingEntity target, boolean critical) {
        botPlayer.swingMainHand();

        double damage = critical ? 6.0 : 4.0;

        if (critical) {
            target.getWorld().spawnParticle(Particle.CRIT, target.getEyeLocation(), 8, 0.3, 0.3, 0.3, 0.05);
        }

        target.damage(damage, botPlayer);
        attackCooldown = ATTACK_COOLDOWN_TICKS;
    }
}

package com.khoablabla.pvpbot.combat;

import net.citizensnpcs.api.npc.NPC;

import org.bukkit.Material;
import org.bukkit.entity.LivingEntity;
import org.bukkit.entity.Player;
import org.bukkit.inventory.ItemStack;
import org.bukkit.inventory.PlayerInventory;

public class ShieldBreaker {

    public void checkAndSwap(NPC npc, LivingEntity target) {
        if (!npc.isSpawned() || !(npc.getEntity() instanceof Player botPlayer)) return;

        PlayerInventory inv = botPlayer.getInventory();
        ItemStack mainHand = inv.getItemInMainHand();

        if (target.isBlocking()) {
            if (!isAxe(mainHand)) {
                for (ItemStack item : inv.getContents()) {
                    if (item != null && isAxe(item)) {
                        inv.setItemInMainHand(item);
                        return;
                    }
                }
            }
        } else {
            if (isAxe(mainHand)) {
                for (ItemStack item : inv.getContents()) {
                    if (item != null && isSword(item)) {
                        inv.setItemInMainHand(item);
                        return;
                    }
                }
            }
        }
    }

    private boolean isAxe(ItemStack item) {
        Material type = item.getType();
        return type == Material.WOODEN_AXE || type == Material.STONE_AXE
                || type == Material.IRON_AXE || type == Material.GOLDEN_AXE
                || type == Material.DIAMOND_AXE || type == Material.NETHERITE_AXE;
    }

    private boolean isSword(ItemStack item) {
        Material type = item.getType();
        return type == Material.WOODEN_SWORD || type == Material.STONE_SWORD
                || type == Material.IRON_SWORD || type == Material.GOLDEN_SWORD
                || type == Material.DIAMOND_SWORD || type == Material.NETHERITE_SWORD;
    }
}

