        return findTarget(npc, DEFAULT_RANGE);
    }

    public LivingEntity findTarget(NPC npc, double range) {
        if (!npc.isSpawned()) return null;

        Entity npcEntity = npc.getEntity();
        if (!(npcEntity instanceof LivingEntity bot)) return null;

        return bot.getNearbyEntities(range, range, range).stream()
                .filter(e -> e instanceof LivingEntity living && !living.isDead())
                .filter(e -> !e.equals(npcEntity))
                .filter(e -> !(e instanceof Player p && (p.getGameMode() == GameMode.CREATIVE || p.getGameMode() == GameMode.SPECTATOR)))
                .map(e -> (LivingEntity) e)
                .min(Comparator.comparingDouble(e -> e.getLocation().distanceSquared(npcEntity.getLocation())))
                .orElse(null);
    }
}

