    private static final double BUNNY_HOP_INTERVAL = 20;
    private static final double STRAFE_DISTANCE = 3.5;
    private static final double STRAFE_RADIUS = 2.0;
    private static final int STRAFE_INTERVAL = 25;

    private int tickCounter = 0;
    private int strafeTimer = 0;
    private boolean strafing = false;

    public void update(NPC npc, LivingEntity target) {
        tickCounter++;
        strafeTimer--;

        if (!npc.isSpawned() || !(npc.getEntity() instanceof Player botPlayer)) return;

        double distance = botPlayer.getLocation().distance(target.getLocation());

        if (distance > STRAFE_DISTANCE) {
            strafing = false;
            npc.getNavigator().setTarget(target, true);

            if (tickCounter % BUNNY_HOP_INTERVAL == 0 && botPlayer.isOnGround()) {
                Vector dir = target.getLocation().toVector()
                        .subtract(botPlayer.getLocation().toVector());
                dir.setY(0).normalize().multiply(0.4);
                dir.setY(0.42);
                botPlayer.setVelocity(dir);
            }
        } else {
            if (!strafing || strafeTimer <= 0) {
                Location strafeDest = calculateStrafePoint(
                        botPlayer.getLocation(), target.getLocation(), STRAFE_RADIUS);
                npc.getNavigator().setTarget(strafeDest);
                npc.getNavigator().getLocalParameters().lookAtFunction(
                        target::getLocation);
                strafing = true;
                strafeTimer = STRAFE_INTERVAL;
            }
        }
    }

    public void stop(NPC npc) {
        if (npc.isSpawned()) {
            npc.getNavigator().cancelNavigation();
        }
        strafing = false;
    }

    private Location calculateStrafePoint(Location botLoc, Location targetLoc, double radius) {
        Vector toBot = botLoc.toVector().subtract(targetLoc.toVector());
        toBot.setY(0);

        if (toBot.lengthSquared() < 0.01) {
            toBot.setX(radius);
        }

        Vector perp = new Vector(-toBot.getZ(), 0, toBot.getX()).normalize().multiply(radius);
        return targetLoc.clone().add(perp);
    }
}

